addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

const ALLOWED_BACKEND_HOSTS = [
  'api.yourdomain.com',
  'backend.yourdomain.com',
  'staging-api.yourdomain.com'
]

const ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS']
const ALLOWED_HEADERS = [
  'Content-Type',
  'Authorization',
  'X-Requested-With',
  'Accept',
  'Origin'
]

const MAX_BODY_SIZE = 10 * 1024 * 1024

async function handleRequest(request) {
  try {
    if (request.method === 'OPTIONS') {
      return handleCORS(request)
    }

    const url = new URL(request.url)
    const backendHost = url.searchParams.get('backend')
    const targetPath = url.searchParams.get('path')

    if (!backendHost || !targetPath) {
      return createErrorResponse('Missing required parameters: backend and path', 400)
    }

    if (!isValidBackendHost(backendHost)) {
      return createErrorResponse('Invalid backend host', 403)
    }

    if (!isValidPath(targetPath)) {
      return createErrorResponse('Invalid path format', 400)
    }

    if (!ALLOWED_METHODS.includes(request.method)) {
      return createErrorResponse('Method not allowed', 405)
    }

    const contentLength = request.headers.get('content-length')
    if (contentLength && parseInt(contentLength) > MAX_BODY_SIZE) {
      return createErrorResponse('Request body too large', 413)
    }

    const backendUrl = `https://${backendHost}${targetPath}`
    
    const sanitizedHeaders = sanitizeHeaders(request.headers)

    const proxyRequest = new Request(backendUrl, {
      method: request.method,
      headers: sanitizedHeaders,
      body: request.method !== 'GET' && request.method !== 'HEAD' ? request.body : null,
      redirect: 'manual'
    })

    const response = await fetch(proxyRequest)

    const responseHeaders = new Headers(response.headers)
    addCORSHeaders(responseHeaders)
    
    removeSecurityHeaders(responseHeaders)

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: responseHeaders
    })

  } catch (error) {
    console.error('Proxy error:', error.message)
    return createErrorResponse('Internal server error', 500)
  }
}

function isValidBackendHost(host) {
  const sanitizedHost = host.toLowerCase().trim()
  
  if (!/^[a-z0-9.-]+$/.test(sanitizedHost)) {
    return false
  }
  
  if (sanitizedHost.includes('..')) {
    return false
  }
  
  return ALLOWED_BACKEND_HOSTS.includes(sanitizedHost)
}

function isValidPath(path) {
  if (!path.startsWith('/')) {
    return false
  }
  
  if (path.includes('..')) {
    return false
  }
  
  if (path.includes('//')) {
    return false
  }
  
  if (!/^[a-zA-Z0-9\/_.-?&=]+$/.test(path)) {
    return false
  }
  
  return true
}

function sanitizeHeaders(headers) {
  const sanitized = new Headers()
  
  const dangerousHeaders = [
    'host',
    'connection',
    'keep-alive',
    'transfer-encoding',
    'upgrade',
    'proxy-authorization',
    'proxy-authenticate'
  ]
  
  for (const [key, value] of headers.entries()) {
    const lowerKey = key.toLowerCase()
    
    if (dangerousHeaders.includes(lowerKey)) {
      continue
    }
    
    if (lowerKey.startsWith('cf-') || lowerKey.startsWith('x-forwarded-')) {
      continue
    }
    
    if (ALLOWED_HEADERS.some(allowed => allowed.toLowerCase() === lowerKey)) {
      sanitized.set(key, value)
    }
  }
  
  return sanitized
}

function removeSecurityHeaders(headers) {
  const headersToRemove = [
    'set-cookie',
    'set-cookie2',
    'www-authenticate',
    'proxy-authenticate'
  ]
  
  headersToRemove.forEach(header => {
    headers.delete(header)
  })
}

function addCORSHeaders(headers) {
  headers.set('Access-Control-Allow-Origin', '*')
  headers.set('Access-Control-Allow-Methods', ALLOWED_METHODS.join(', '))
  headers.set('Access-Control-Allow-Headers', ALLOWED_HEADERS.join(', '))
  headers.set('Access-Control-Max-Age', '86400')
  headers.set('Access-Control-Expose-Headers', 'Content-Length, Content-Type')
}

function handleCORS(request) {
  const headers = new Headers()
  addCORSHeaders(headers)
  
  return new Response(null, {
    status: 204,
    headers: headers
  })
}

function createErrorResponse(message, status) {
  const headers = new Headers({
    'Content-Type': 'application/json'
  })
  addCORSHeaders(headers)
  
  return new Response(JSON.stringify({ error: message }), {
    status: status,
    headers: headers
  })
}